class RecentCounter {
public:
    queue<int> que;

    RecentCounter() {

    }

    int ping(int t) {
        int temp = t - 3000;
        que.push(t);

        while(!que.empty() && que.front() < temp){
            que.pop();
        }

        return que.size();
    }
};

